&style.procedural;
stringfalsecollator_get_sort_key Collatorobject stringstring
Retourne la clé de la collation pour une chaîne. Les clés de collation peuvent être comparées directement au lieu de chaînes, néanmoins elles sont spécifiques à l'implémentation et peuvent changer entre les versions de la bibliothèque ICU. Les clés de tri sont généralement seulement utiles dans les bases de données ou autres circonstances où les appels de fonctions sont extrêmement chers.

  &reftitle.returnvalues;

Retourne la clé de collation pour la chaîne, &return.falseforfailure;.
  &return.falseproblem;

  &reftitle.examples;



    Exemple collator_get_sort_key


<?php

$s1 = 'Hello';

$coll = collator_create('en_US');
$res  = collator_get_sort_key($coll, $s1);

echo bin2hex($res);
?>


    &example.outputs.similar;

     3832404046010901dc08






    Collator::getSortKey : exemple avec usort


<?php

$data = [
    [ 'name' => '🇳🇱 Derick Rethans', 'linked_account' => 'https://phpc.social/users/derickr' ],
    [ 'name' => 'Elephpant', 'linked_account' => 'https://phpc.social/phpc' ],
    [ 'name' => '🇫🇷 Marcus Bointon', 'linked_account' => 'https://phpc.social/users/Synchro' ],
];

/* Créer le collateur */
$col = new Collator('en');

/* Trier les lettres majuscules avant les minuscules */
$col->setAttribute(Collator::CASE_FIRST, Collator::UPPER_FIRST);

/* Utiliser une fonction définie par l'utilisateur avec sort, qui supprime les émojis */
usort(
    $data,
    function($a, $b) use ($col) {
        /* Supprimer la classe de caractères 'S' (Symboles) et les espaces
         * (avec trim) */
        $aName = trim(preg_replace('/\p{S}+/u', '', $a['name']));
        $bName = trim(preg_replace('/\p{S}+/u', '', $b['name']));

								/* Créer la clé de tri */
        $aKey = $col->getSortKey($aName);
        $bKey = $col->getSortKey($bName);

								/* Utiliser la clé de tri pour déterminer l'ordre des éléments */
        return $aKey <=> $bKey;
    }
);

var_dump($data);
?>


